@page "/"
@using SkiaSharp
@using SkiaSharp.Views.Blazor

<h3>Wheel Event Test</h3>
<SKCanvasView OnPaintSurface="OnPaintSurface" style="width:400px;height:300px;border:1px solid black;" />
<p id="status">Waiting for wheel events...</p>

@code {
    private void OnPaintSurface(SKPaintSurfaceEventArgs e)
    {
        var canvas = e.Surface.Canvas;
        canvas.Clear(SKColors.CornflowerBlue);
        using var font = new SKFont();
        using var paint = new SKPaint { Color = SKColors.White, IsAntialias = true };
        canvas.DrawText("Scroll wheel over this canvas", 20, 150, font, paint);
        Console.WriteLine($"SUCCESS: rendered {e.Info.Width}x{e.Info.Height}");
    }
}
